(function(){'use strict';const SW_URL = '/sw.js';if('serviceWorker' in navigator){window.addEventListener('load',()=>{navigator.serviceWorker.register(SW_URL,{scope:'/'}).then((reg)=>{console.log('[PWA]Service Worker kaydedildi:',reg.scope);reg.addEventListener('updatefound',()=>{const newWorker = reg.installing;if(!newWorker)return;newWorker.addEventListener('statechange',()=>{if(newWorker.state === 'activated' && navigator.serviceWorker.controller){if(window.bildirim){window.bildirim('Yeni sürüm hazır — yenilemek için[OK]basın','bilgi');}}});});}).catch((err)=>{console.warn('[PWA]Service Worker kayıt başarısız:',err);});});}let deferredPrompt = null;window.addEventListener('beforeinstallprompt',(e)=>{e.preventDefault();deferredPrompt = e;document.dispatchEvent(new CustomEvent('pwa-installable',{detail:{canInstall:true}}));});window.pwaInstallPrompt = function(){if(!deferredPrompt)return false;deferredPrompt.prompt();deferredPrompt.userChoice.then((choice)=>{deferredPrompt = null;return choice.outcome === 'accepted';});};window.addEventListener('appinstalled',()=>{if(window.bildirim){window.bildirim('Uygulama ana ekrana eklendi!','basari');}deferredPrompt = null;});})();